+            let _ = stream.write_all(bad_request);
+            let _ = stream.flush();
+            return;
+        };
+
+        let start_time = std::time::Instant::now();
+
+        // Build a proper Request object
+        let method = match parsed.method.to_uppercase().as_str() {
+            "GET" => Method::Get,
+            "POST" => Method::Post,
+            "PUT" => Method::Put,
+            "DELETE" => Method::Delete,
+            "PATCH" => Method::Patch,
+            "HEAD" => Method::Head,
+            "OPTIONS" => Method::Options,
